"use client";

// REMINDER: React Compiler is not compatible with TanStack Table v8
// https://github.com/TanStack/table/issues/5567
"use no memo";

import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/custom/table";
import { DataTableFilterCommand } from "@/components/data-table/data-table-filter-command";
import { DataTableFilterControls } from "@/components/data-table/data-table-filter-controls";
import { DataTablePagination } from "@/components/data-table/data-table-pagination";
import { DataTableProvider } from "@/components/data-table/data-table-provider";
import { DataTableToolbar } from "@/components/data-table/data-table-toolbar";
import type { DataTableFilterField, SheetField } from "@/components/data-table/types";
import { useLocalStorage } from "@/hooks/use-local-storage";
import { getColumnVisibilityKey } from "@/lib/constants/local-storage";
import type { SchemaDefinition } from "@/lib/store/schema/types";
import { cn } from "@/lib/utils";
import type {
  ColumnDef,
  ColumnFiltersState,
  PaginationState,
  Row,
  RowSelectionState,
  SortingState,
  TableOptions,
  Table as TTable,
  VisibilityState,
} from "@tanstack/react-table";
import {
  flexRender,
  getCoreRowModel,
  getFacetedMinMaxValues,
  getFacetedRowModel,
  getFacetedUniqueValues,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
} from "@tanstack/react-table";
import type { FetchNextPageOptions, FetchPreviousPageOptions, RefetchOptions } from "@tanstack/react-query";
import * as React from "react";

export interface DataTableProps<TData, TValue> {
  // ── Core ──────────────────────────────────────────────────────────────────
  data: TData[];
  columns: ColumnDef<TData, TValue>[];
  filterFields?: DataTableFilterField<TData>[];
  // BYOS — required so component is not coupled to a specific schema
  schema: SchemaDefinition;
  tableId: string;

  // ── State defaults ────────────────────────────────────────────────────────
  defaultColumnFilters?: ColumnFiltersState;
  defaultSorting?: SortingState;
  defaultColumnVisibility?: VisibilityState;
  defaultRowSelection?: RowSelectionState;
  defaultPagination?: PaginationState;

  // ── Row behaviour ─────────────────────────────────────────────────────────
  getRowId?: TableOptions<TData>["getRowId"];
  getRowClassName?: (row: Row<TData>) => string;

  // ── Server-side facets ────────────────────────────────────────────────────
  getFacetedUniqueValues?: (
    table: TTable<TData>,
    columnId: string,
  ) => Map<string, number>;
  getFacetedMinMaxValues?: (
    table: TTable<TData>,
    columnId: string,
  ) => [number, number] | undefined;

  // ── Column features ───────────────────────────────────────────────────────
  enableColumnOrdering?: boolean;
  enableColumnResizing?: boolean;

  // ── Loading / fetch state ─────────────────────────────────────────────────
  isLoading?: boolean;
  isFetching?: boolean;
  totalRows?: number;
  filterRows?: number;
  totalRowsFetched?: number;

  // ── Infinite scroll (optional — use DataTableInfinite for full support) ───
  hasNextPage?: boolean;
  fetchNextPage?: (options?: FetchNextPageOptions) => Promise<unknown>;
  fetchPreviousPage?: (options?: FetchPreviousPageOptions) => Promise<unknown>;
  refetch?: (options?: RefetchOptions) => void;

  // ── Sheet / detail panel ──────────────────────────────────────────────────
  sheetFields?: SheetField<TData>[];
  renderSheetTitle?: (props: { row?: Row<TData> }) => React.ReactNode;

  // ── Render slots ──────────────────────────────────────────────────────────
  /** Passed to DataTableToolbar — renders after the reset button and before view options */
  renderActions?: () => React.ReactNode;
  /** Renders below the toolbar, above the table (e.g. a chart) */
  renderChart?: () => React.ReactNode;
  /** Renders at the bottom of the sidebar (e.g. a footer) */
  renderSidebarFooter?: () => React.ReactNode;
}

export function DataTable<TData, TValue>({
  columns,
  data,
  defaultColumnFilters = [],
  defaultSorting = [],
  defaultColumnVisibility = {},
  defaultPagination = { pageIndex: 0, pageSize: 10 },
  filterFields = [],
  getFacetedUniqueValues: externalGetFacetedUniqueValues,
  getFacetedMinMaxValues: externalGetFacetedMinMaxValues,
  isLoading,
  schema,
  tableId,
  renderActions,
  renderChart,
  renderSidebarFooter,
}: DataTableProps<TData, TValue>) {
  const [columnFilters, setColumnFilters] =
    React.useState<ColumnFiltersState>(defaultColumnFilters);
  const [sorting, setSorting] =
    React.useState<SortingState>(defaultSorting);
  const [pagination, setPagination] =
    React.useState<PaginationState>(defaultPagination);
  const [columnVisibility, setColumnVisibility] =
    useLocalStorage<VisibilityState>(
      getColumnVisibilityKey(tableId),
      defaultColumnVisibility,
    );

  // Reset pagination when filters change to avoid showing empty pages
  React.useEffect(() => {
    setPagination((prev) => ({ ...prev, pageIndex: 0 }));
  }, [columnFilters]);

  // Custom getFacetedUniqueValues that handles array column values
  const customGetFacetedUniqueValues = React.useCallback(
    (table: TTable<TData>, columnId: string) => () => {
      const facets = getFacetedUniqueValues<TData>()(table, columnId)();
      const customFacets = new Map();
      for (const [key, value] of facets as Map<unknown, number>) {
        if (Array.isArray(key)) {
          for (const k of key) {
            customFacets.set(k, (customFacets.get(k) || 0) + value);
          }
        } else {
          customFacets.set(key, (customFacets.get(key) || 0) + value);
        }
      }
      return customFacets;
    },
    [],
  );

  const table = useReactTable({
    data,
    columns,
    state: { columnFilters, sorting, columnVisibility, pagination },
    onColumnVisibilityChange: setColumnVisibility,
    onColumnFiltersChange: setColumnFilters,
    onSortingChange: setSorting,
    onPaginationChange: setPagination,
    getSortedRowModel: getSortedRowModel(),
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getFacetedRowModel: getFacetedRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getFacetedMinMaxValues: getFacetedMinMaxValues(),
    getFacetedUniqueValues: customGetFacetedUniqueValues,
    enableFilters: true,
    enableColumnFilters: true,
  });

  // Adapter signature for DataTableProvider
  const getFacetedUniqueValuesForProvider = React.useCallback(
    (table: TTable<TData>, columnId: string): Map<string, number> => {
      // Prefer externally-provided (server-side) facets over computed ones
      if (externalGetFacetedUniqueValues) {
        return externalGetFacetedUniqueValues(table, columnId);
      }
      return customGetFacetedUniqueValues(table, columnId)();
    },
    [customGetFacetedUniqueValues, externalGetFacetedUniqueValues],
  );

  return (
    <DataTableProvider
      table={table}
      columns={columns}
      filterFields={filterFields}
      columnFilters={columnFilters}
      sorting={sorting}
      pagination={pagination}
      isLoading={isLoading}
      getFacetedUniqueValues={getFacetedUniqueValuesForProvider}
      getFacetedMinMaxValues={externalGetFacetedMinMaxValues}
    >
      <div className="flex h-full w-full flex-col gap-3 sm:flex-row">
        <div
          className={cn(
            "hidden w-full p-1 sm:block sm:min-w-52 sm:max-w-52 sm:self-start md:min-w-64 md:max-w-64",
            "group-data-[expanded=false]/controls:hidden",
          )}
        >
          <DataTableFilterControls />
          {renderSidebarFooter?.()}
        </div>
        <div className="flex max-w-full flex-1 flex-col gap-4 overflow-hidden p-1">
          <DataTableFilterCommand schema={schema} tableId={tableId} />
          {renderChart?.()}
          <DataTableToolbar renderActions={renderActions} />
          <div className="rounded-md border">
            <Table>
              <TableHeader className="bg-muted/50">
                {table.getHeaderGroups().map((headerGroup) => (
                  <TableRow
                    key={headerGroup.id}
                    className="hover:bg-transparent"
                  >
                    {headerGroup.headers.map((header) => (
                      <TableHead key={header.id}>
                        {header.isPlaceholder
                          ? null
                          : flexRender(
                              header.column.columnDef.header,
                              header.getContext(),
                            )}
                      </TableHead>
                    ))}
                  </TableRow>
                ))}
              </TableHeader>
              <TableBody>
                {table.getRowModel().rows?.length ? (
                  table.getRowModel().rows.map((row) => (
                    <TableRow
                      key={row.id}
                      data-state={row.getIsSelected() && "selected"}
                    >
                      {row.getVisibleCells().map((cell) => (
                        <TableCell key={cell.id}>
                          {flexRender(
                            cell.column.columnDef.cell,
                            cell.getContext(),
                          )}
                        </TableCell>
                      ))}
                    </TableRow>
                  ))
                ) : (
                  <TableRow>
                    <TableCell
                      colSpan={columns.length}
                      className="h-24 text-center"
                    >
                      No results.
                    </TableCell>
                  </TableRow>
                )}
              </TableBody>
            </Table>
          </div>
          <DataTablePagination />
        </div>
      </div>
    </DataTableProvider>
  );
}

import { DataTableFilterField } from "@/components/data-table/types";
import type {
  ColumnDef,
  ColumnFiltersState,
  PaginationState,
  RowSelectionState,
  SortingState,
  Table,
  VisibilityState,
} from "@tanstack/react-table";
import { createContext, useContext, useMemo } from "react";
import { ControlsProvider } from "../../providers/controls";
import { DataTableStoreSync } from "./data-table-store-sync";

// REMINDER: read about how to move controlled state out of the useReactTable hook
// https://github.com/TanStack/table/discussions/4005#discussioncomment-7303569

interface DataTableStateContextType {
  columnFilters: ColumnFiltersState;
  sorting: SortingState;
  rowSelection: RowSelectionState;
  columnOrder: string[];
  columnVisibility: VisibilityState;
  pagination: PaginationState;
  enableColumnOrdering: boolean;
}

interface DataTableBaseContextType<TData = unknown, TValue = unknown> {
  table: Table<TData>;
  filterFields: DataTableFilterField<TData>[];
  columns: ColumnDef<TData, TValue>[];
  isLoading?: boolean;
  getFacetedUniqueValues?: (
    table: Table<TData>,
    columnId: string,
  ) => Map<string, number>;
  getFacetedMinMaxValues?: (
    table: Table<TData>,
    columnId: string,
  ) => undefined | [number, number];
}

interface DataTableContextType<TData = unknown, TValue = unknown>
  extends DataTableStateContextType,
    DataTableBaseContextType<TData, TValue> {}

export const DataTableContext = createContext<DataTableContextType<
  any,
  any
> | null>(null);

export function DataTableProvider<TData, TValue>({
  children,
  ...props
}: Partial<DataTableStateContextType> &
  DataTableBaseContextType<TData, TValue> & {
    children: React.ReactNode;
  }) {
  const value = useMemo(
    // eslint-disable-next-line react-hooks/preserve-manual-memoization
    () => ({
      ...props,
      columnFilters: props.columnFilters ?? [],
      sorting: props.sorting ?? [],
      rowSelection: props.rowSelection ?? {},
      columnOrder: props.columnOrder ?? [],
      columnVisibility: props.columnVisibility ?? {},
      pagination: props.pagination ?? { pageIndex: 0, pageSize: 10 },
      enableColumnOrdering: props.enableColumnOrdering ?? false,
    }),
    [
      props.columnFilters,
      props.sorting,
      props.rowSelection,
      props.columnOrder,
      props.columnVisibility,
      props.pagination,
      props.table,
      props.filterFields,
      props.columns,
      props.enableColumnOrdering,
      props.isLoading,
      props.getFacetedUniqueValues,
      props.getFacetedMinMaxValues,
    ],
  );

  return (
    <DataTableContext.Provider value={value}>
      <ControlsProvider>
        <DataTableStoreSync />
        {children}
      </ControlsProvider>
    </DataTableContext.Provider>
  );
}

export function useDataTable<TData, TValue>() {
  const context = useContext(DataTableContext);

  if (!context) {
    throw new Error("useDataTable must be used within a DataTableProvider");
  }

  return context as DataTableContextType<TData, TValue>;
}

"use client";

import { Kbd } from "@/components/custom/kbd";
import { useDataTable } from "@/components/data-table/data-table-provider";
import { Button } from "@/components/ui/button";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { useHotKey } from "@/hooks/use-hot-key";
import { formatCompactNumber } from "@/lib/format";
import { useControls } from "@/providers/controls";
import { PanelLeftClose, PanelLeftOpen } from "lucide-react";
import { useMemo } from "react";
import { DataTableFilterControlsDrawer } from "./data-table-filter-controls-drawer";
import { DataTableResetButton } from "./data-table-reset-button";
import { DataTableViewOptions } from "./data-table-view-options";

interface DataTableToolbarProps {
  renderActions?: () => React.ReactNode;
}

export function DataTableToolbar({ renderActions }: DataTableToolbarProps) {
  const { table, isLoading, columnFilters } = useDataTable();
  const { open, setOpen } = useControls();
  useHotKey(() => setOpen((prev) => !prev), "b");
  const filters = table.getState().columnFilters;

  const rows = useMemo(
    () => ({
      total: table.getCoreRowModel().rows.length,
      filtered: table.getFilteredRowModel().rows.length,
    }),
    [isLoading, columnFilters, table],
  );

  return (
    <div className="flex flex-wrap items-center justify-between gap-4">
      <div className="flex flex-wrap items-center gap-2">
        <TooltipProvider>
          <Tooltip delayDuration={100}>
            <TooltipTrigger asChild>
              <Button
                size="sm"
                variant="ghost"
                onClick={() => setOpen((prev) => !prev)}
                className="hidden gap-2 sm:flex"
              >
                {open ? (
                  <>
                    <PanelLeftClose className="h-4 w-4" />
                    <span className="hidden md:block">Hide Controls</span>
                  </>
                ) : (
                  <>
                    <PanelLeftOpen className="h-4 w-4" />
                    <span className="hidden md:block">Show Controls</span>
                  </>
                )}
              </Button>
            </TooltipTrigger>
            <TooltipContent side="right">
              <p>
                Toggle controls with{" "}
                <Kbd className="ml-1 text-muted-foreground group-hover:text-accent-foreground">
                  <span className="mr-1">⌘</span>
                  <span>B</span>
                </Kbd>
              </p>
            </TooltipContent>
          </Tooltip>
        </TooltipProvider>
        <div className="block sm:hidden">
          <DataTableFilterControlsDrawer />
        </div>
        <div>
          <p className="hidden text-sm text-muted-foreground sm:block">
            <span className="font-mono font-medium">
              {formatCompactNumber(rows.filtered)}
            </span>{" "}
            of{" "}
            <span className="font-mono font-medium">
              {formatCompactNumber(rows.total)}
            </span>{" "}
            row(s) <span className="sr-only sm:not-sr-only">filtered</span>
          </p>
          <p className="block text-sm text-muted-foreground sm:hidden">
            <span className="font-mono font-medium">
              {formatCompactNumber(rows.filtered)}
            </span>{" "}
            row(s)
          </p>
        </div>
      </div>
      <div className="ml-auto flex items-center gap-2">
        {filters.length ? <DataTableResetButton /> : null}
        {renderActions?.()}
        <DataTableViewOptions />
      </div>
    </div>
  );
}

"use client";

import { useDataTable } from "@/components/data-table/data-table-provider";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  ChevronLeft,
  ChevronRight,
  ChevronsLeft,
  ChevronsRight,
} from "lucide-react";
import { useMemo } from "react";

export function DataTablePagination() {
  const { table, pagination, columnFilters } = useDataTable();
  const pageCount = useMemo(
    () => table.getPageCount(),
    [columnFilters, pagination.pageSize, table],
  );

  return (
    <div className="flex items-center justify-end space-x-4 md:space-x-6 lg:space-x-8">
      <div className="flex items-center space-x-2">
        <p className="text-sm font-medium">Rows per page</p>
        <Select
          value={`${pagination.pageSize}`}
          onValueChange={(value) => {
            table.setPageSize(Number(value));
          }}
        >
          <SelectTrigger className="h-8 w-[70px]">
            <SelectValue placeholder={pagination.pageSize} />
          </SelectTrigger>
          <SelectContent side="top">
            {[10, 20, 30, 40, 50].map((pageSize) => (
              <SelectItem key={pageSize} value={`${pageSize}`}>
                {pageSize}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>
      <div className="flex items-center justify-center text-sm font-medium">
        Page {pagination.pageIndex + 1} of {pageCount}
      </div>
      <div className="flex items-center space-x-2">
        <Button
          variant="outline"
          className="hidden h-8 w-8 p-0 lg:flex"
          onClick={() => {
            table.setPageIndex(0);
          }}
          disabled={!table.getCanPreviousPage()}
        >
          <span className="sr-only">Go to first page</span>
          <ChevronsLeft className="h-4 w-4" />
        </Button>
        <Button
          variant="outline"
          className="h-8 w-8 p-0"
          onClick={() => {
            table.previousPage();
          }}
          disabled={!table.getCanPreviousPage()}
        >
          <span className="sr-only">Go to previous page</span>
          <ChevronLeft className="h-4 w-4" />
        </Button>
        <Button
          variant="outline"
          className="h-8 w-8 p-0"
          onClick={() => {
            table.nextPage();
          }}
          disabled={!table.getCanNextPage()}
        >
          <span className="sr-only">Go to next page</span>
          <ChevronRight className="h-4 w-4" />
        </Button>
        <Button
          variant="outline"
          className="hidden h-8 w-8 p-0 lg:flex"
          onClick={() => {
            table.setPageIndex(table.getPageCount() - 1);
          }}
          disabled={!table.getCanNextPage()}
        >
          <span className="sr-only">Go to last page</span>
          <ChevronsRight className="h-4 w-4" />
        </Button>
      </div>
    </div>
  );
}

"use client";

import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/custom/accordion";
import { useDataTable } from "@/components/data-table/data-table-provider";
import type React from "react";
import { DataTableFilterCheckbox } from "./data-table-filter-checkbox";
import { DataTableFilterInput } from "./data-table-filter-input";
import { DataTableFilterResetButton } from "./data-table-filter-reset-button";
import { DataTableFilterSlider } from "./data-table-filter-slider";
import { DataTableFilterTimerange } from "./data-table-filter-timerange";

// FIXME: use @container (especially for the slider element) to restructure elements

// TODO: only pass the columns to generate the filters!
// https://tanstack.com/table/v8/docs/framework/react/examples/filters

export function DataTableFilterControls() {
  const { filterFields } = useDataTable();
  return (
    <Accordion
      type="multiple"
      defaultValue={filterFields
        ?.filter(({ defaultOpen }) => defaultOpen)
        ?.map(({ value }) => value as string)}
    >
      {filterFields?.map((field) => {
        const value = field.value as string;
        return (
          <AccordionItem key={value} value={value} className="border-none">
            <AccordionTrigger className="w-full px-2 py-0 hover:no-underline data-[state=closed]:text-muted-foreground data-[state=open]:text-foreground focus-within:data-[state=closed]:text-foreground hover:data-[state=closed]:text-foreground">
              <div className="flex w-full items-center justify-between gap-2 truncate py-2 pr-2">
                <div className="flex items-center gap-2 truncate">
                  <p className="text-sm font-medium">{field.label}</p>
                  {value !== field.label.toLowerCase() &&
                  !field.commandDisabled ? (
                    <p className="mt-px truncate font-mono text-[10px] text-muted-foreground">
                      {value}
                    </p>
                  ) : null}
                </div>
                <DataTableFilterResetButton {...field} />
              </div>
            </AccordionTrigger>
            <AccordionContent>
              {/* REMINDER: avoid the focus state to be cut due to overflow-hidden */}
              {/* REMINDER: need to move within here because of accordion height animation */}
              <div className="p-1">
                {(() => {
                  switch (field.type) {
                    case "checkbox": {
                      return <DataTableFilterCheckbox {...field} />;
                    }
                    case "slider": {
                      return <DataTableFilterSlider {...field} />;
                    }
                    case "input": {
                      return <DataTableFilterInput {...field} />;
                    }
                    case "timerange": {
                      return <DataTableFilterTimerange {...field} />;
                    }
                  }
                })()}
              </div>
            </AccordionContent>
          </AccordionItem>
        );
      })}
    </Accordion>
  );
}

import { Kbd } from "@/components/custom/kbd";
import { Button } from "@/components/ui/button";
import {
  Drawer,
  DrawerClose,
  DrawerContent,
  DrawerDescription,
  DrawerFooter,
  DrawerHeader,
  DrawerTitle,
  DrawerTrigger,
} from "@/components/ui/drawer";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { useHotKey } from "@/hooks/use-hot-key";
import { useMediaQuery } from "@/hooks/use-media-query";
import { VisuallyHidden } from "@radix-ui/react-visually-hidden";
import { FilterIcon } from "lucide-react";
import React from "react";
import { DataTableFilterControls } from "./data-table-filter-controls";

export function DataTableFilterControlsDrawer() {
  const triggerButtonRef = React.useRef<HTMLButtonElement>(null);
  const isMobile = useMediaQuery("(max-width: 640px)");

  useHotKey(() => {
    triggerButtonRef.current?.click();
  }, "b");

  return (
    <Drawer>
      <TooltipProvider>
        <Tooltip delayDuration={100}>
          <TooltipTrigger asChild>
            <DrawerTrigger asChild>
              <Button
                ref={isMobile ? triggerButtonRef : null}
                variant="ghost"
                size="icon"
                className="h-9 w-9"
              >
                <FilterIcon className="h-4 w-4" />
              </Button>
            </DrawerTrigger>
          </TooltipTrigger>
          <TooltipContent side="right">
            <p>
              Toggle controls with{" "}
              <Kbd className="ml-1 text-muted-foreground group-hover:text-accent-foreground">
                <span className="mr-1">⌘</span>
                <span>B</span>
              </Kbd>
            </p>
          </TooltipContent>
        </Tooltip>
      </TooltipProvider>
      <DrawerContent className="max-h-[calc(100dvh-4rem)]">
        <VisuallyHidden>
          <DrawerHeader>
            <DrawerTitle>Filters</DrawerTitle>
            <DrawerDescription>Adjust your table filters</DrawerDescription>
          </DrawerHeader>
        </VisuallyHidden>
        <div className="flex-1 overflow-y-auto px-4">
          <DataTableFilterControls />
        </div>
        <DrawerFooter>
          <DrawerClose asChild>
            <Button variant="outline" className="w-full">
              Close
            </Button>
          </DrawerClose>
        </DrawerFooter>
      </DrawerContent>
    </Drawer>
  );
}

"use client";

import {Kbd} from "@/components/custom/kbd";
import {useDataTable} from "@/components/data-table/data-table-provider";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
  CommandSeparator,
} from "@/components/ui/command";
import {Separator} from "@/components/ui/separator";
import {useHotKey} from "@/hooks/use-hot-key";
import {useLocalStorage} from "@/hooks/use-local-storage";
import {getCommandHistoryKey} from "@/lib/constants/local-storage";
import {formatCompactNumber} from "@/lib/format";
import type {SchemaDefinition} from "@/lib/store/schema/types";
import {cn} from "@/lib/utils";
import {formatDistanceToNow} from "date-fns";
import {LoaderCircle,Search,X} from "lucide-react";
import {useEffect,useMemo,useRef,useState} from "react";
import type {DataTableFilterField} from "../types";
import {
  columnFiltersParserFromSchema,
  getFieldOptions,
  getFilterValue,
  getWordByCaretPosition,
  replaceInputByFieldType,
} from "./utils";

// FIXME: there is an issue on cmdk if I wanna only set a single slider value...

interface DataTableFilterCommandProps {
  // Schema definition for parsing/serializing filter values (BYOS)
  schema: SchemaDefinition;
  // Unique ID for this table (used to namespace localStorage)
  tableId?: string;
}

export function DataTableFilterCommand({
  schema,
  tableId="default",
}: DataTableFilterCommandProps) {
  const {
    table,
    isLoading,
    filterFields: _filterFields,
    getFacetedUniqueValues,
  }=useDataTable();
  const columnFilters=table.getState().columnFilters;
  const inputRef=useRef<HTMLInputElement>(null);
  const [open,setOpen]=useState<boolean>(false);
  const [currentWord,setCurrentWord]=useState<string>("");
  // Guard to prevent effect cycle when serializing
  const isSerializingRef=useRef(false);
  const filterFields=useMemo(
    () => _filterFields?.filter((i) => !i.commandDisabled),
    [_filterFields],
  );
  const columnParser=useMemo(
    () => columnFiltersParserFromSchema({schema,filterFields}),
    [schema,filterFields],
  );
  const [inputValue,setInputValue]=useState<string>(
    columnParser.serialize(columnFilters),
  );
  const [lastSearches,setLastSearches]=useLocalStorage<
    {
      search: string;
      timestamp: number;
    }[]
  >(getCommandHistoryKey(tableId),[]);

  useEffect(() => {
    // Skip if this update came from serialization (prevents infinite loop)
    if (isSerializingRef.current) {
      isSerializingRef.current=false;
      return;
    }
    // TODO: we could check for ARRAY_DELIMITER or SLIDER_DELIMITER to auto-set filter when typing
    if (currentWord!==""&&open) return;
    // reset
    if (currentWord!==""&&!open) setCurrentWord("");
    // avoid recursion
    if (inputValue.trim()===""&&!open) return;

    const searchParams=columnParser.parse(inputValue);

    const currentFilters=table.getState().columnFilters;
    const currentEnabledFilters=currentFilters.filter((filter) => {
      const field=_filterFields?.find((field) => field.value===filter.id);
      return !field?.commandDisabled;
    });
    const currentDisabledFilters=currentFilters.filter((filter) => {
      const field=_filterFields?.find((field) => field.value===filter.id);
      return field?.commandDisabled;
    });



    for (const key of Object.keys(searchParams)) {
      const value=searchParams[key as keyof typeof searchParams];
      table.getColumn(key)?.setFilterValue(value);
    }
    const currentFiltersToReset=currentEnabledFilters.filter((filter) => {
      return !(filter.id in searchParams);
    });
    for (const filter of currentFiltersToReset) {
      table.getColumn(filter.id)?.setFilterValue(undefined);
    }

    // eslint-disable-next-line react-hooks/exhaustive-deps
  },[inputValue,open,currentWord]);

  useEffect(() => {
    // REMINDER: only update the input value if the command is closed (avoids jumps while open)
    if (!open) {
      // Set flag to prevent the parse effect from running after serialization
      isSerializingRef.current=true;
      setInputValue(columnParser.serialize(columnFilters));
    }
  },[columnFilters,filterFields,open,columnParser]);

  useHotKey(() => setOpen((open) => !open),"k");

  useEffect(() => {
    if (open) {
      inputRef?.current?.focus();
    }
  },[open]);

  return (
    <div>
      <button
        type="button"
        className={cn(
          "group flex w-full items-center rounded-lg border border-input bg-background px-3 text-muted-foreground ring-offset-background focus-within:outline-none focus-within:ring-2 focus-within:ring-ring focus-within:ring-offset-2 hover:bg-accent/50 hover:text-accent-foreground",
          open? "hidden":"visible",
        )}
        onClick={() => setOpen(true)}
      >
        {isLoading? (
          <LoaderCircle className="mr-2 h-4 w-4 shrink-0 animate-spin text-muted-foreground opacity-50 group-hover:text-popover-foreground" />
        ):(
          <Search className="mr-2 h-4 w-4 shrink-0 text-muted-foreground opacity-50 group-hover:text-popover-foreground" />
        )}
        <span className="h-11 w-full max-w-sm truncate py-3 text-left text-sm outline-none disabled:cursor-not-allowed disabled:opacity-50 md:max-w-xl lg:max-w-4xl xl:max-w-5xl">
          {inputValue.trim()? (
            <span className="text-foreground">{inputValue}</span>
          ):(
            <span>Search data table...</span>
          )}
        </span>
        <Kbd className="ml-auto text-muted-foreground group-hover:text-accent-foreground">
          <span className="mr-1">⌘</span>
          <span>K</span>
        </Kbd>
      </button>
      <Command
        className={cn(
          "overflow-visible rounded-lg border border-border shadow-md dark:bg-muted/50 [&>div]:border-none",
          open? "visible":"hidden",
        )}
        filter={(value,search,keywords) =>
          getFilterValue({value,search,keywords,currentWord})
        }
      // loop
      >
        <CommandInput
          ref={inputRef}
          value={inputValue}
          onValueChange={setInputValue}
          onKeyDown={(e) => {
            if (e.key==="Escape") inputRef?.current?.blur();
          }}
          onBlur={() => {
            setOpen(false);
            // FIXME: doesnt reflect the jumps
            // FIXME: will save non-existing searches
            // TODO: extract into function
            const search=inputValue.trim();
            if (!search) return;
            const timestamp=Date.now();
            const searchIndex=lastSearches.findIndex(
              (item) => item.search===search,
            );
            if (searchIndex!==-1) {
              lastSearches[searchIndex].timestamp=timestamp;
              setLastSearches(lastSearches);
              return;
            }
            setLastSearches([...lastSearches,{search,timestamp}]);
            return;
          }}
          onInput={(e) => {
            const caretPosition=e.currentTarget?.selectionStart||-1;
            const value=e.currentTarget?.value||"";
            const word=getWordByCaretPosition({value,caretPosition});
            setCurrentWord(word);
          }}
          placeholder="Search data table..."
          className="text-foreground"
        />
        <div className="relative">
          <div className="absolute top-2 z-10 w-full overflow-hidden rounded-lg border border-border bg-popover text-popover-foreground shadow-md outline-none animate-in">
            {/* default height is 300px but in case of more, we'd like to tease the user */}
            <CommandList className="max-h-[310px]">
              <CommandGroup heading="Filter">
                {filterFields.map((field) => {
                  if (typeof field.value!=="string") return null;
                  if (inputValue.includes(`${field.value}:`)) return null;
                  // TBD: should we handle this in the component?
                  return (
                    <CommandItem
                      key={field.value}
                      value={field.value}
                      onMouseDown={(e) => {
                        e.preventDefault();
                        e.stopPropagation();
                      }}
                      onSelect={(value) => {
                        setInputValue((prev) => {
                          if (currentWord.trim()==="") {
                            const input=`${prev}${value}`;
                            return `${input}:`;
                          }
                          // lots of cheat
                          const isStarting=currentWord===prev;
                          const prefix=isStarting? "":" ";
                          const input=prev.replace(
                            `${prefix}${currentWord}`,
                            `${prefix}${value}`,
                          );
                          return `${input}:`;
                        });
                        setCurrentWord(`${value}:`);
                      }}
                      className="group"
                    >
                      {field.value}
                      <CommandItemSuggestions field={field} />
                    </CommandItem>
                  );
                })}
              </CommandGroup>
              <CommandSeparator />
              <CommandGroup heading="Query">
                {filterFields?.map((field) => {
                  if (typeof field.value!=="string") return null;
                  if (!currentWord.includes(`${field.value}:`)) return null;

                  const column=table.getColumn(field.value);
                  const facetedValue=
                    getFacetedUniqueValues?.(table,field.value)||
                    column?.getFacetedUniqueValues();

                  const options=getFieldOptions({field});

                  return options.map((optionValue) => {
                    return (
                      <CommandItem
                        key={`${String(field.value)}:${optionValue}`}
                        value={`${String(field.value)}:${optionValue}`}
                        onMouseDown={(e) => {
                          e.preventDefault();
                          e.stopPropagation();
                        }}
                        onSelect={(value) => {
                          setInputValue((prev) =>
                            replaceInputByFieldType({
                              prev,
                              currentWord,
                              optionValue,
                              value,
                              field,
                            }),
                          );
                          setCurrentWord("");
                        }}
                      >
                        {`${optionValue}`}
                        {facetedValue?.has(optionValue)? (
                          <span className="ml-auto font-mono text-muted-foreground">
                            {formatCompactNumber(
                              facetedValue.get(optionValue)||0,
                            )}
                          </span>
                        ):null}
                      </CommandItem>
                    );
                  });
                })}
              </CommandGroup>
              <CommandSeparator />
              <CommandGroup heading="Suggestions">
                {lastSearches
                  ?.sort((a,b) => b.timestamp-a.timestamp)
                  .slice(0,5)
                  .map((item) => {
                    return (
                      <CommandItem
                        key={`suggestion:${item.search}`}
                        value={`suggestion:${item.search}`}
                        onMouseDown={(e) => {
                          e.preventDefault();
                          e.stopPropagation();
                        }}
                        onSelect={(value) => {
                          const search=value.replace("suggestion:","");
                          setInputValue(`${search} `);
                          setCurrentWord("");
                        }}
                        className="group"
                      >
                        {item.search}
                        <span className="ml-auto truncate text-muted-foreground/80 group-aria-[selected=true]:block">
                          {formatDistanceToNow(item.timestamp,{
                            addSuffix: true,
                          })}
                        </span>
                        <button
                          type="button"
                          onMouseDown={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                          }}
                          onClick={(e) => {
                            e.preventDefault();
                            e.stopPropagation();
                            // TODO: extract into function
                            setLastSearches(
                              lastSearches.filter(
                                (i) => i.search!==item.search,
                              ),
                            );
                          }}
                          className="ml-1 hidden rounded-md p-0.5 hover:bg-background group-aria-[selected=true]:block"
                        >
                          <X className="h-4 w-4" />
                        </button>
                      </CommandItem>
                    );
                  })}
              </CommandGroup>
              <CommandEmpty>No results found.</CommandEmpty>
            </CommandList>
            <div
              className="flex flex-wrap justify-between gap-3 border-t bg-accent/50 px-2 py-1.5 text-sm text-accent-foreground"
              cmdk-footer=""
            >
              <div className="flex flex-wrap gap-3">
                <span>
                  Use <Kbd variant="outline">↑</Kbd>{" "}
                  <Kbd variant="outline">↓</Kbd> to navigate
                </span>
                <span>
                  <Kbd variant="outline">Enter</Kbd> to query
                </span>
                <span>
                  <Kbd variant="outline">Esc</Kbd> to close
                </span>
                <Separator orientation="vertical" className="my-auto h-3" />
                <span>
                  Union: <Kbd variant="outline">regions:a,b</Kbd>
                </span>
                <span>
                  Range: <Kbd variant="outline">p95:59-340</Kbd>
                </span>
                <span>
                  Spaces: <Kbd variant="outline">name:&quot;a b&quot;</Kbd>
                </span>
              </div>
              {lastSearches.length? (
                <button
                  type="button"
                  className="text-muted-foreground hover:text-accent-foreground"
                  onMouseDown={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                  }}
                  onClick={() => setLastSearches([])}
                >
                  Clear suggestions
                </button>
              ):null}
            </div>
          </div>
        </div>
      </Command>
    </div>
  );
}

// function CommandItemType<TData>

function CommandItemSuggestions<TData>({
  field,
}: {
  field: DataTableFilterField<TData>;
}) {
  const {table,getFacetedMinMaxValues,getFacetedUniqueValues}=
    useDataTable();
  const value=field.value as string;
  switch (field.type) {
    case "checkbox": {
      return (
        <span className="ml-1 hidden truncate text-muted-foreground/80 group-aria-[selected=true]:block">
          {getFacetedUniqueValues
            ? Array.from(getFacetedUniqueValues(table,value)?.keys()||[])
              .map((value) => `[${value}]`)
              .join(" ")
            :field.options?.map(({value}) => `[${value}]`).join(" ")}
        </span>
      );
    }
    case "slider": {
      const [min,max]=getFacetedMinMaxValues?.(table,value)||[
        field.min,
        field.max,
      ];
      return (
        <span className="ml-1 hidden truncate text-muted-foreground/80 group-aria-[selected=true]:block">
          [{min} - {max}]
        </span>
      );
    }
    case "input": {
      return (
        <span className="ml-1 hidden truncate text-muted-foreground/80 group-aria-[selected=true]:block">
          [{`${String(field.value)}`} input]
        </span>
      );
    }
    default: {
      return null;
    }
  }
}

import {
  ARRAY_DELIMITER,
  RANGE_DELIMITER,
  SLIDER_DELIMITER,
} from "@/lib/delimiters";
import {isArrayOfDates} from "@/lib/is-array";
import type {FieldBuilder,SchemaDefinition} from "@/lib/store/schema/types";
import type {ColumnFiltersState} from "@tanstack/react-table";
import type {DataTableFilterField} from "../types";

/**
 * Extracts the word from the given string at the specified caret position.
 */
export function getWordByCaretPosition({
  value,
  caretPosition,
}: {
  value: string;
  caretPosition: number;
}) {
  let start=caretPosition;
  let end=caretPosition;

  while (start>0&&value[start-1]!==" ") start--;
  while (end<value.length&&value[end]!==" ") end++;

  const word=value.substring(start,end);
  return word;
}

/**
 * Quote a value if it contains spaces
 */
function quoteIfNeeded(val: string|number|boolean|undefined): string {
  const str=`${val}`;
  if (str.includes(" ")) {
    return `"${str}"`;
  }
  return str;
}

export function replaceInputByFieldType<TData>({
  prev,
  currentWord,
  optionValue,
  value,
  field,
}: {
  prev: string;
  currentWord: string;
  optionValue?: string|number|boolean|undefined; // FIXME: use DataTableFilterField<TData>["options"][number];
  value: string;
  field: DataTableFilterField<TData>;
}) {
  switch (field.type) {
    case "checkbox": {
      if (currentWord.includes(ARRAY_DELIMITER)) {
        const words=currentWord.split(ARRAY_DELIMITER);
        words[words.length-1]=quoteIfNeeded(optionValue);
        const input=prev.replace(currentWord,words.join(ARRAY_DELIMITER));
        return `${input.trim()} `;
      }
      break;
    }
    case "slider": {
      if (currentWord.includes(SLIDER_DELIMITER)) {
        const words=currentWord.split(SLIDER_DELIMITER);
        words[words.length-1]=`${optionValue}`;
        const input=prev.replace(currentWord,words.join(SLIDER_DELIMITER));
        return `${input.trim()} `;
      }
      break;
    }
    case "timerange": {
      if (currentWord.includes(RANGE_DELIMITER)) {
        const words=currentWord.split(RANGE_DELIMITER);
        words[words.length-1]=`${optionValue}`;
        const input=prev.replace(currentWord,words.join(RANGE_DELIMITER));
        return `${input.trim()} `;
      }
      break;
    }
    default: {
      break;
    }
  }

  // Fallback / default behavior
  const quotedValue=quoteIfNeeded(optionValue)||value;
  const input=prev.replace(
    currentWord,
    `${String(field.value)}:${quotedValue}`,
  );
  return `${input.trim()} `;
}

export function getFieldOptions<TData>({
  field,
}: {
  field: DataTableFilterField<TData>;
}) {
  switch (field.type) {
    case "slider": {
      return field.options?.length
        ? field.options
          .map(({value}) => value)
          .sort((a,b) => Number(a)-Number(b))
          .filter(notEmpty)
        :Array.from(
          {length: field.max-field.min+1},
          (_,i) => field.min+i,
        )||[];
    }
    default: {
      return field.options?.map(({value}) => value).filter(notEmpty)||[];
    }
  }
}

export function getFilterValue({
  value,
  search,
  currentWord,
}: {
  value: string;
  search: string;
  keywords?: string[]|undefined;
  currentWord: string;
}): number {
  /**
   * @example value "suggestion:public:true regions,ams,gru,fra"
   */
  if (value.startsWith("suggestion:")) {
    const rawValue=value.toLowerCase().replace("suggestion:","");
    if (rawValue.includes(search)) return 1;
    return 0;
  }

  /** */
  if (value.toLowerCase().includes(currentWord.toLowerCase())) return 1;

  /**
   * @example checkbox [filter, query] = ["regions", "ams,gru,fra"]
   * @example slider [filter, query] = ["p95", "0-3000"]
   * @example input [filter, query] = ["name", "api"]
   */
  const [filter,query]=currentWord.toLowerCase().split(":");
  if (query&&value.startsWith(`${filter}:`)) {
    if (query.includes(ARRAY_DELIMITER)) {
      /**
       * array of n elements
       * @example queries = ["ams", "gru", "fra"]
       */
      const queries=query.split(ARRAY_DELIMITER);
      const rawValue=value.toLowerCase().replace(`${filter}:`,"");
      if (
        queries.some((item,i) => item===rawValue&&i!==queries.length-1)
      )
        return 0;
      if (queries.some((item) => rawValue.includes(item))) return 1;
    }
    if (query.includes(SLIDER_DELIMITER)) {
      /**
       * range between 2 elements
       * @example queries = ["0", "3000"]
       */
      const queries=query.split(SLIDER_DELIMITER);
      const rawValue=value.toLowerCase().replace(`${filter}:`,"");

      const rawValueAsNumber=Number.parseInt(rawValue);
      const queryAsNumber=Number.parseInt(queries[0]);

      if (queryAsNumber<rawValueAsNumber) {
        if (rawValue.includes(queries[1])) return 1;
        return 0;
      }
      return 0;
    }
    const rawValue=value.toLowerCase().replace(`${filter}:`,"");
    if (rawValue.includes(query)) return 1;
  }
  return 0;
}

export function getFieldValueByType<TData>({
  field,
  value,
}: {
  field?: DataTableFilterField<TData>;
  value: unknown;
}) {
  if (!field) return null;

  switch (field.type) {
    case "slider": {
      if (Array.isArray(value)) {
        return value.join(SLIDER_DELIMITER);
      }
      return value;
    }
    case "checkbox": {
      if (Array.isArray(value)) {
        return value.join(ARRAY_DELIMITER);
      }
      // REMINER: inversed logic
      if (typeof value==="string") {
        return value.split(ARRAY_DELIMITER);
      }
      return value;
    }
    case "timerange": {
      if (Array.isArray(value)) {
        if (isArrayOfDates(value)) {
          return value.map((date) => date.getTime()).join(RANGE_DELIMITER);
        }
        return value.join(RANGE_DELIMITER);
      }
      if (value instanceof Date) {
        return value.getTime();
      }
      return value;
    }
    default: {
      return value;
    }
  }
}

export function notEmpty<TValue>(
  value: TValue|null|undefined,
): value is TValue {
  return value!==null&&value!==undefined;
}

/**
 * Tokenize input string, respecting quoted values
 *
 * Examples:
 * - `name:john regions:ams` → [["name", "john"], ["regions", "ams"]]
 * - `name:"john doe" regions:ams` → [["name", "john doe"], ["regions", "ams"]]
 * - `url:"https://example.com/path with spaces"` → [["url", "https://example.com/path with spaces"]]
 */
export function tokenizeFilterInput(input: string): Array<[string,string]> {
  const results: Array<[string,string]>=[];
  const trimmed=input.trim();

  // Regex to match: key:"quoted value" or key:unquoted_value
  // This handles:
  // - key:"value with spaces"
  // - key:'value with spaces' (single quotes)
  // - key:valueWithoutSpaces
  const regex=/(\w+):(?:"([^"]*)"|'([^']*)'|(\S+))/g;

  let match;
  while ((match=regex.exec(trimmed))!==null) {
    const key=match[1];
    // Value is in group 2 (double quotes), group 3 (single quotes), or group 4 (unquoted)
    const value=match[2]??match[3]??match[4];
    if (key&&value!==undefined) {
      results.push([key,value]);
    }
  }

  return results;
}

/**
 * Serialize a value, adding quotes if it contains spaces
 */
export function serializeFilterValue(value: string): string {
  if (value.includes(" ")) {
    return `"${value}"`;
  }
  return value;
}

/**
 * Schema-based column filters parser for BYOS
 *
 * This parser works with the new schema system instead of nuqs ParserBuilder.
 */
export function columnFiltersParserFromSchema<TData>({
  schema,
  filterFields,
}: {
  schema: SchemaDefinition;
  filterFields: DataTableFilterField<TData>[];
}) {
  return {
    parse: (inputValue: string) => {
      // Use tokenizer that respects quoted values
      const tokens=tokenizeFilterInput(inputValue);
      const values=tokens.reduce(
        (prev,[name,value]) => {
          prev[name]=value;
          return prev;
        },
        {} as Record<string,string>,
      );

      const searchParams=Object.entries(values).reduce(
        (prev,[key,value]) => {
          const fieldBuilder=schema[key] as FieldBuilder<unknown>|undefined;
          if (!fieldBuilder) return prev;

          const parsed=fieldBuilder._config.parse(value);
          if (parsed!==null) {
            prev[key]=parsed;
          }
          return prev;
        },
        {} as Record<string,unknown>,
      );

      return searchParams;
    },
    serialize: (columnFilters: ColumnFiltersState) => {
      const values=columnFilters.reduce((prev,curr) => {
        const {commandDisabled}=filterFields?.find(
          (field) => curr.id===field.value,
        )||{commandDisabled: true};
        const fieldBuilder=schema[curr.id] as
          |FieldBuilder<unknown>
          |undefined;

        if (commandDisabled||!fieldBuilder) return prev;

        const serialized=fieldBuilder._config.serialize(curr.value);
        if (!serialized) return prev;

        // Wrap in quotes if value contains spaces
        const quotedValue=serializeFilterValue(serialized);
        return `${prev}${curr.id}:${quotedValue} `;
      },"");

      return values;
    },
  };
}

"use client";

import { InputWithAddons } from "@/components/custom/input-with-addons";
import { useDataTable } from "@/components/data-table/data-table-provider";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";
import { Skeleton } from "@/components/ui/skeleton";
import { formatCompactNumber } from "@/lib/format";
import { cn } from "@/lib/utils";
import { Search } from "lucide-react";
import { useState } from "react";
import type { DataTableCheckboxFilterField } from "./types";

export function DataTableFilterCheckbox<TData>({
  value: _value,
  options,
  component,
}: DataTableCheckboxFilterField<TData>) {
  const value = _value as string;
  const [inputValue, setInputValue] = useState("");
  const { table, columnFilters, isLoading, getFacetedUniqueValues } =
    useDataTable();
  const column = table.getColumn(value);
  // REMINDER: avoid using column?.getFilterValue()
  const filterValue = columnFilters.find((i) => i.id === value)?.value;
  const facetedValue =
    getFacetedUniqueValues?.(table, value) || column?.getFacetedUniqueValues();

  const Component = component;

  // filter out the options based on the input value
  const filterOptions = options?.filter(
    (option) =>
      inputValue === "" ||
      option.label.toLowerCase().includes(inputValue.toLowerCase()),
  );

  // CHECK: it could be filterValue or searchValue
  const filters = filterValue
    ? Array.isArray(filterValue)
      ? filterValue
      : [filterValue]
    : [];

  // REMINDER: if no options are defined, while fetching data, we should show a skeleton
  if (isLoading && !filterOptions?.length)
    return (
      <div className="grid divide-y rounded-lg border border-border">
        {Array.from({ length: 3 }).map((_, index) => (
          <div
            key={index}
            className="flex items-center justify-between gap-2 px-2 py-2.5"
          >
            <Skeleton className="h-4 w-4 rounded-sm" />
            <Skeleton className="h-4 w-full rounded-sm" />
          </div>
        ))}
      </div>
    );

  return (
    <div className="grid gap-2">
      {options && options.length > 4 ? (
        <InputWithAddons
          placeholder="Search"
          leading={<Search className="mt-0.5 h-4 w-4" />}
          containerClassName="h-9 rounded-lg"
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
        />
      ) : null}
      {/* FIXME: due to the added max-h and overflow-y-auto, the hover state and border is laying on top of the scroll bar */}
      <div className="max-h-[200px] overflow-y-auto rounded-lg border border-border empty:border-none">
        {filterOptions
          // TODO: we shoudn't sort the options here, instead filterOptions should be sorted by default
          // .sort((a, b) => a.label.localeCompare(b.label))
          ?.map((option, index) => {
            const checked = filters.includes(option.value);

            return (
              <div
                key={String(option.value)}
                className={cn(
                  "group relative flex items-center space-x-2 px-2 py-2.5 hover:bg-accent/50",
                  index !== filterOptions.length - 1 ? "border-b" : undefined,
                )}
              >
                <Checkbox
                  id={`${value}-${option.value}`}
                  checked={checked}
                  onCheckedChange={(checked) => {
                    const newValue = checked
                      ? [...(filters || []), option.value]
                      : filters?.filter((value) => option.value !== value);
                    column?.setFilterValue(
                      newValue?.length ? newValue : undefined,
                    );
                  }}
                />
                <Label
                  htmlFor={`${value}-${option.value}`}
                  className="flex w-full items-center justify-center gap-1 truncate text-foreground/70 group-hover:text-accent-foreground"
                >
                  {Component ? (
                    <Component {...option} />
                  ) : (
                    <span className="truncate font-normal">{option.label}</span>
                  )}
                  <span className="ml-auto flex items-center justify-center font-mono text-xs">
                    {isLoading ? (
                      <Skeleton className="h-4 w-4" />
                    ) : facetedValue?.has(option.value) ? (
                      formatCompactNumber(facetedValue.get(option.value) || 0)
                    ) : null}
                  </span>
                  <button
                    type="button"
                    onClick={() => column?.setFilterValue([option.value])}
                    className={cn(
                      "absolute inset-y-0 right-0 hidden font-normal text-muted-foreground backdrop-blur-sm hover:text-foreground group-hover:block",
                      "rounded-md ring-offset-background focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                    )}
                  >
                    <span className="px-2">only</span>
                  </button>
                </Label>
              </div>
            );
          })}
      </div>
    </div>
  );
}

"use client";

import {InputWithAddons} from "@/components/custom/input-with-addons";
import {useDataTable} from "@/components/data-table/data-table-provider";
import {Label} from "@/components/ui/label";
import {useDebounce} from "@/hooks/use-debounce";
import {Search} from "lucide-react";
import {useEffect,useState} from "react";
import type {DataTableInputFilterField} from "./types";

function getFilter(filterValue: unknown) {
  return typeof filterValue==="string"? filterValue:null;
}

export function DataTableFilterInput<TData>({
  value: _value,
}: DataTableInputFilterField<TData>) {
  const value=_value as string;
  const {table,columnFilters}=useDataTable();
  const column=table.getColumn(value);
  const filterValue=columnFilters.find((i) => i.id===value)?.value;
  const filters=getFilter(filterValue);
  const [input,setInput]=useState<string|null>(filters);

  const debouncedInput=useDebounce(input,500);

  useEffect(() => {
    const newValue=debouncedInput?.trim()===""? null:debouncedInput;
    if (debouncedInput===null) return;
    column?.setFilterValue(newValue);
  },[debouncedInput,column]);

  useEffect(() => {
    if (debouncedInput?.trim()!==filters) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setInput(filters);
    }
  },[filters,debouncedInput]);

  return (
    <div className="grid w-full gap-1.5">
      <Label htmlFor={value} className="sr-only px-2 text-muted-foreground">
        {value}
      </Label>
      <InputWithAddons
        placeholder="Search"
        leading={<Search className="mt-0.5 h-4 w-4" />}
        containerClassName="h-9 rounded-lg"
        name={value}
        id={value}
        value={input||""}
        onChange={(e) => setInput(e.target.value)}
      />
    </div>
  );
}

"use client";

import {InputWithAddons} from "@/components/custom/input-with-addons";
import {Slider} from "@/components/custom/slider";
import {useDataTable} from "@/components/data-table/data-table-provider";
import {Label} from "@/components/ui/label";
import {useDebounce} from "@/hooks/use-debounce";
import {isArrayOfNumbers} from "@/lib/is-array";
import {useEffect,useState} from "react";
import type {DataTableSliderFilterField} from "./types";

function getFilter(filterValue: unknown) {
  return typeof filterValue==="number"
    ? [filterValue,filterValue]
    :Array.isArray(filterValue)&&isArrayOfNumbers(filterValue)
      ? filterValue.length===1
        ? [filterValue[0],filterValue[0]]
        :filterValue
      :null;
}

// TODO: discuss if we even need the `defaultMin` and `defaultMax`
export function DataTableFilterSlider<TData>({
  value: _value,
  min: defaultMin,
  max: defaultMax,
}: DataTableSliderFilterField<TData>) {
  const value=_value as string;
  const {table,columnFilters,getFacetedMinMaxValues}=useDataTable();
  const column=table.getColumn(value);
  const filterValue=columnFilters.find((i) => i.id===value)?.value;
  const filters=getFilter(filterValue);
  const [input,setInput]=useState<number[]|null>(filters);
  const [min,max]=getFacetedMinMaxValues?.(table,value)||
    column?.getFacetedMinMaxValues()||[defaultMin,defaultMax];

  const debouncedInput=useDebounce(input,500);

  useEffect(() => {
    if (debouncedInput?.length===2) {
      column?.setFilterValue(debouncedInput);
    }
  },[debouncedInput,column]);

  useEffect(() => {
    if (debouncedInput?.length!==2) {
      return;
    }
    if (!filters) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setInput(null);
    } else if (
      debouncedInput[0]!==filters[0]||
      debouncedInput[1]!==filters[1]
    ) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setInput(filters);
    }
  },[filters,debouncedInput]);

  return (
    <div className="grid gap-2">
      <div className="flex items-center gap-4">
        <div className="grid w-full gap-1.5">
          <Label
            htmlFor={`min-${value}`}
            className="px-2 text-muted-foreground"
          >
            Min.
          </Label>
          <InputWithAddons
            placeholder="from"
            trailing="ms"
            containerClassName="mb-2 h-9 rounded-lg"
            type="number"
            name={`min-${value}`}
            id={`min-${value}`}
            value={`${input?.[0]??min}`}
            min={min}
            max={max}
            onChange={(e) =>
              setInput((prev) => [Number(e.target.value),prev?.[1]||max])
            }
          />
        </div>
        <div className="grid w-full gap-1.5">
          <Label
            htmlFor={`max-${value}`}
            className="px-2 text-muted-foreground"
          >
            Max.
          </Label>
          <InputWithAddons
            placeholder="to"
            trailing="ms"
            containerClassName="mb-2 h-9 rounded-lg"
            type="number"
            name={`max-${value}`}
            id={`max-${value}`}
            value={`${input?.[1]??max}`}
            min={min}
            max={max}
            onChange={(e) =>
              setInput((prev) => [prev?.[0]||min,Number(e.target.value)])
            }
          />
        </div>
      </div>
      <Slider
        min={min}
        max={max}
        value={input?.length===2? input:[min,max]}
        onValueChange={(values) => setInput(values)}
      />
    </div>
  );
}

"use client";

import { DatePickerWithRange } from "@/components/custom/date-picker-with-range";
import { useDataTable } from "@/components/data-table/data-table-provider";
import { isArrayOfDates } from "@/lib/is-array";
import { useMemo } from "react";
import type { DateRange } from "react-day-picker";
import type { DataTableTimerangeFilterField } from "./types";

export function DataTableFilterTimerange<TData>({
  value: _value,
  presets,
}: DataTableTimerangeFilterField<TData>) {
  const value = _value as string;
  const { table, columnFilters } = useDataTable();
  const column = table.getColumn(value);
  const filterValue = columnFilters.find((i) => i.id === value)?.value;

  const date: DateRange | undefined = useMemo(
    () =>
      filterValue instanceof Date
        ? { from: filterValue, to: undefined }
        : Array.isArray(filterValue) && isArrayOfDates(filterValue)
          ? { from: filterValue?.[0], to: filterValue?.[1] }
          : undefined,
    [filterValue],
  );

  const setDate = (date: DateRange | undefined) => {
    if (!date) return; // TODO: remove from search params if columnFilter is removed
    if (date.from && !date.to) {
      column?.setFilterValue([date.from]);
    }
    if (date.to && date.from) {
      column?.setFilterValue([date.from, date.to]);
    }
  };

  return <DatePickerWithRange {...{ date, setDate, presets }} />;
}

